module width_8to16(
    input clk,
    input rst_n,
    input valid_in,
    input [7:0] data_in,
    output reg valid_out,
    output reg [15:0] data_out
);

reg [7:0] upper_data;
reg upper_valid;
reg lower_valid;
reg [7:0] lower_data;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        upper_data <= 0;
        upper_valid <= 0;
        lower_valid <= 0;
        lower_data <= 0;
        valid_out <= 0;
        data_out <= 0;
    end else begin
        if (valid_in) begin
            upper_data <= data_in;
            upper_valid <= 1;
            lower_valid <= 0;
        end else if (upper_valid) begin
            lower_data <= upper_data;
            lower_valid <= 1;
            upper_valid <= 0;
        end

        if (upper_valid && lower_valid) begin
            data_out <= {upper_data, lower_data};
            valid_out <= 1;
        end else begin
            valid_out <= 0;
        end
    end
end

endmodule
